"""Activity: Concurrency Court

Fifteen no-code scenarios and definitions covering Python's three concurrency tools -- asyncio, threading, and multiprocessing -- plus the honesty option of using none of them, the GIL (Global Interpreter Lock) defined from scratch, race conditions, process memory isolation, and why blocking calls stall an event loop. It opens by defining io-bound and cpu-bound from scratch, since every scenario after that leans on those two words. Each question's explanation is the real content: this activity teaches the mental model for choosing a tool, not just the vocabulary.
"""
import json, sys


# -- Crypto / obfuscation --
_KEY_A = "6c2dcf483f36bfc652bfa5b0fb12d1cc56a7af1afc6ee753d1a9be99f670ec9c"
_KEY_B = "d9a0e3d269d3fae6ff4a5a41fce3358229523c282b409f7b09f54d08b67281b2"
import base64 as _b64, hashlib as _hl, hmac as _hm, json as _js, zlib as _zl

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000

# Split runtime key. This is obfuscation only; do not treat it as a secret.
def _xor_bytes(a, b):
    return bytes(x ^ y for x, y in zip(a, b))

def _runtime_key():
    return _xor_bytes(bytes.fromhex(_KEY_A), bytes.fromhex(_KEY_B))

def _derive_key(answers):
    return _hl.pbkdf2_hmac("sha256", "|".join(answers).encode(), _SALT, _KDF_ITERS)

def _stream(key, length):
    ks, i = b"", 0
    while len(ks) < length:
        ks += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return ks[:length]

def _decrypt(blob_hex, answers):
    blob    = bytes.fromhex(blob_hex)
    key     = _derive_key(answers)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    return bytes(a ^ b for a, b in zip(ct, _stream(key, len(ct)))).decode()

def _item_key(label):
    return _hm.new(_runtime_key(), label.encode(), _hl.sha256).digest()

def _open_secret(blob_text, label):
    try:
        blob = _b64.b85decode(blob_text.encode())
        key = _item_key(label)
        ct, mac = blob[:-32], blob[-32:]
        if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
            return None
        pt = _xor_bytes(ct, _stream(key, len(ct)))
        data = _js.loads(_zl.decompress(pt).decode())
        return data if isinstance(data, dict) else None
    except Exception:
        return None
